# Deobfuscated Code

Here's the deobfuscated version with explanations:

```javascript
// Physics simulation constants
const TWO_PI = 6.283;
const GOLDEN_RATIO = 1.618;
const SQRT_HALF = 0.707;

// Simulation parameters
const params = {
  attractionForce: 4000,
  dampingCoefficient: 0.004,
  amplification: 0.92,
  centeringForce: 0.0003,
  maxParticles: 40,
  streamDecay: 0.04,
  theta: 0.06
};

// Node definitions (particles in the network)
const nodes = [
  {id: 'hub', label: 'Hub', r: 26, x: 400, y: 300, vx: 0, vy: 0},
  {id: 'alpha', label: 'Alpha', r: 16, x: 500, y: 200, vx: 0, vy: 0},
  {id: 'beta', label: 'Beta', r: 16, x: 300, y: 400, vx: 0, vy: 0},
  {id: 'gamma', label: 'Gamma', r: 14, x: 250, y: 180, vx: 0, vy: 0},
  {id: 'delta', label: 'Delta', r: 14, x: 550, y: 380, vx: 0, vy: 0},
  {id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0}
];

// Link definitions (connections between nodes)
const links = [
  {a: 'hub', b: 'alpha', rest: 160, k: 0.006},
  {a: 'hub', b: 'beta', rest: 160, k: 0.005},
  {a: 'hub', b: 'gamma', rest: 170, k: 0.004},
  {a: 'hub', b: 'delta', rest: 170, k: 0.004},
  {a: 'hub', b: 'epsilon', rest: 180, k: 0.003},
  {a: 'alpha', b: 'beta', rest: 200, k: 0.002},
  {a: 'gamma', b: 'delta', rest: 220, k: 0.002},
  {a: 'beta', b: 'epsilon', rest: 200, k: 0.002}
];

// Camera/view state
let camera = {x: 400, y: 300, zoom: 1};
let targetCamera = {x: 400, y: 300, zoom: 1};

// Particle system
let particles = [];
let frameCount = 0;

// Find node by ID
function getNode(id) {
  for (let i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// Physics simulation step
function simulate() {
  // Repulsive forces between all nodes
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const dx = nodes[i].x - nodes[j].x;
      const dy = nodes[i].y - nodes[j].y;
      const distance = Math.sqrt(dx*dx + dy*dy) || 1;
      const force = params.attractionForce / (distance * distance);
      const fx = (dx / distance) * force;
      const fy = (dy / distance) * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // Attractive spring forces along links
  for (let i = 0; i < links.length; i++) {
    const nodeA = getNode(links[i].a);
    const nodeB = getNode(links[i].b);
    if (!nodeA || !nodeB) continue;

    const dx = nodeB.x - nodeA.x;
    const dy = nodeB.y - nodeA.y;
    const distance = Math.sqrt(dx*dx + dy*dy) || 1;
    const delta = distance - links[i].rest;
    const force = (links[i].k || params.dampingCoefficient) * delta;

    nodeA.vx += (dx / distance) * force;
    nodeA.vy += (dy / distance) * force;
    nodeB.vx -= (dx / distance) * force;
    nodeB.vy -= (dy / distance) * force;
  }

  // Apply damping and centering forces
  for (let i = 0; i < nodes.length; i++) {
    nodes[i].vx *= params.amplification;
    nodes[i].vy *= params.amplification;
    nodes[i].vx += (400 - nodes[i].x) * params.centeringForce;
    nodes[i].vy += (300 - nodes[i].y) * params.centeringForce;
    nodes[i].x += nodes[i].vx;
    nodes[i].y += nodes[i].vy;
  }
}

// Spawn new particles from nodes
function spawnParticles() {
  if (particles.length >= params.maxParticles) return;

  const sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
  const angle = Math.random() * TWO_PI;
  const speed = (0.3 + Math.random() * SQRT_HALF);

  particles.push({
    x: sourceNode.x,
    y: sourceNode.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * GOLDEN_RATIO * SQRT_HALF
  });
}

// Update particles
function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    const p = particles[i];
    p.x += p.vx;
    p.y += p.vy;
    p.vx *= (1 - params.streamDecay * 0.125);
    p.vy *= (1 - params.streamDecay * 0.125);
    p.age++;

    if (p.age > p.maxAge) {
      particles.splice(i, 1);
    }
  }
}

// Update camera smoothly
function updateCamera() {
  camera.x += (targetCamera.x - camera.x) * params.theta;
  camera.y += (targetCamera.y - camera.y) * params.theta;
  camera.zoom += (targetCamera.zoom - camera.zoom) * params.theta;
}

// Main animation loop
function animationFrame() {
  simulate();
  updateParticles();
  updateCamera();

  if (frameCount % 3 === 0) {
    spawnParticles();
  }
  frameCount++;
}

// Run at ~60fps
setInterval(animationFrame, 16);
```

## What It Does

This is a **network graph physics simulation** that:

1. **Creates a node network** with 6 connected nodes (hub, alpha, beta, gamma, delta, epsilon)
2. **Applies physics forces**:
   - Repulsive forces between all nodes (they push apart)
   - Spring forces along links (connected nodes pull together)
   - Damping to reduce oscillation
   - Centering force to keep nodes near the center

3. **Spawns particles** from nodes that move in random directions and fade out over time
4. **Smoothly animates the camera** view as it follows the network
5. **Runs continuously** updating the simulation every 16ms

It's essentially a **force-directed graph visualization with particle effects** - like a visual representation of a network or relationship diagram with dynamic, organic movement.
